numeros = [0, 0, 1, 0] # Se crea una lista llamada numeros que contiene los números 0, 0, 1 y 0.

if any(numeros): # Se utiliza la función any() para verificar si al menos uno de los elementos en la lista numeros es verdadero (no cero). La función any() devuelve True si al menos un elemento es verdadero, y False si todos los elementos son falsos (cero en este caso).
    print("Al menos un número es no cero.") # Si la condición se evalúa como verdadera, se muestra un mensaje indicando que al menos un número en la lista es no cero. En este caso, el número 1 es no cero, por lo que la condición se evalúa como verdadera y se muestra el mensaje correspondiente.

# Salida:
# Al menos un número es no cero.